import React from 'react';
import Menu from './js/components/Menu/Menu.js';
import SignInPage from './js/components/SignInPage/SignInPage.tsx';
import RegisterPage from './js/components/RegisterPage/RegisterPage.js';

import { useState } from "react";

const App = () => {
  const [page, setPage] = useState('SignInPage');
    return(
      (<div>
        <Menu showPage = {setPage}/>
          {page === 'SignInPage' && <SignInPage/>}
          {page === 'RegisterPage' && <RegisterPage/>}
      </div>)
    );
}

export default App;
